SELECT DISTINCT ?song ?songLabel
WHERE {
  ?song p:P1545 ?positionStatement.
  ?positionStatement
    ps:P1545 ?position;
    pq:P1343 wd:Q321844;
    pq:P585 ?date.
  FILTER(year(?date) = 2020)
  FILTER(?position <= 100)
  FILTER NOT EXISTS { ?song wdt:P420 wd:Q1659734 }
  OPTIONAL { ?song rdfs:label ?songLabel. FILTER(lang(?songLabel) = "en") }
}

